deployment.program:
import credits.aleo;

program veilsub_collab_v1.aleo;

record CollabAgreement:
    owner as address.private;
    partner as address.private;
    collab_id as field.private;
    split_pct as u8.private;
    partner_split as u8.private;
    content_hash as field.private;
    created_at as u32.private;
    active as boolean.private;

record CollabReceipt:
    owner as address.private;
    collab_id as field.private;
    amount as u64.private;
    total_amount as u64.private;
    content_id as field.private;

struct CollabKey:
    creator_a_hash as field;
    creator_b_hash as field;
    collab_id as field;

mapping collab_exists:
    key as field.public;
    value as boolean.public;

mapping collab_active:
    key as field.public;
    value as boolean.public;

mapping collab_revenue:
    key as field.public;
    value as u64.public;

mapping collab_content_count:
    key as field.public;
    value as u64.public;

function create_collab:
    input r0 as address.private;
    input r1 as field.private;
    input r2 as u8.private;
    input r3 as field.private;
    gte r2 1u8 into r4;
    assert.eq r4 true;
    lte r2 99u8 into r5;
    assert.eq r5 true;
    sub 100u8 r2 into r6;
    hash.psd2 self.caller into r7 as field;
    hash.psd2 r0 into r8 as field;
    cast self.caller r0 r1 r2 r6 r3 0u32 true into r9 as CollabAgreement.record;
    cast r0 self.caller r1 r6 r2 r3 0u32 true into r10 as CollabAgreement.record;
    cast r7 r8 r1 into r11 as CollabKey;
    hash.psd2 r11 into r12 as field;
    async create_collab r12 into r13;
    output r9 as CollabAgreement.record;
    output r10 as CollabAgreement.record;
    output r13 as veilsub_collab_v1.aleo/create_collab.future;

finalize create_collab:
    input r0 as field.public;
    get.or_use collab_exists[r0] false into r1;
    not r1 into r2;
    assert.eq r2 true;
    set true into collab_exists[r0];
    set true into collab_active[r0];
    set 0u64 into collab_revenue[r0];
    set 0u64 into collab_content_count[r0];

function split_payment:
    input r0 as CollabAgreement.record;
    input r1 as credits.aleo/credits.record;
    input r2 as u64.private;
    input r3 as field.private;
    assert.eq r0.active true;
    gt r2 0u64 into r4;
    assert.eq r4 true;
    cast r2 into r5 as u128;
    cast r0.split_pct into r6 as u128;
    mul r5 r6 into r7;
    div r7 100u128 into r8;
    cast r8 into r9 as u64;
    sub r2 r9 into r10;
    call credits.aleo/transfer_private r1 r0.partner r10 into r11 r12;
    cast self.caller r0.collab_id r9 r2 r3 into r13 as CollabReceipt.record;
    cast r0.partner r0.collab_id r10 r2 r3 into r14 as CollabReceipt.record;
    hash.psd2 self.caller into r15 as field;
    hash.psd2 r0.partner into r16 as field;
    cast r15 r16 r0.collab_id into r17 as CollabKey;
    hash.psd2 r17 into r18 as field;
    async split_payment r18 r2 into r19;
    output r13 as CollabReceipt.record;
    output r14 as CollabReceipt.record;
    output r11 as credits.aleo/credits.record;
    output r12 as credits.aleo/credits.record;
    output r19 as veilsub_collab_v1.aleo/split_payment.future;

finalize split_payment:
    input r0 as field.public;
    input r1 as u64.public;
    get.or_use collab_active[r0] false into r2;
    assert.eq r2 true;
    get.or_use collab_revenue[r0] 0u64 into r3;
    add r3 r1 into r4;
    set r4 into collab_revenue[r0];

function publish_collab_content:
    input r0 as CollabAgreement.record;
    input r1 as field.public;
    input r2 as field.public;
    assert.eq r0.active true;
    hash.psd2 self.caller into r3 as field;
    hash.psd2 r0.partner into r4 as field;
    cast r3 r4 r0.collab_id into r5 as CollabKey;
    hash.psd2 r5 into r6 as field;
    async publish_collab_content r6 into r7;
    output r7 as veilsub_collab_v1.aleo/publish_collab_content.future;

finalize publish_collab_content:
    input r0 as field.public;
    get.or_use collab_active[r0] false into r1;
    assert.eq r1 true;
    get.or_use collab_content_count[r0] 0u64 into r2;
    add r2 1u64 into r3;
    set r3 into collab_content_count[r0];

function end_collab:
    input r0 as CollabAgreement.record;
    hash.psd2 self.caller into r1 as field;
    hash.psd2 r0.partner into r2 as field;
    cast r1 r2 r0.collab_id into r3 as CollabKey;
    hash.psd2 r3 into r4 as field;
    async end_collab r4 into r5;
    output r5 as veilsub_collab_v1.aleo/end_collab.future;

finalize end_collab:
    input r0 as field.public;
    set false into collab_active[r0];
